#include <stdio.h>
#include <unistd.h>
#include <getopt.h>
#include <stdlib.h>
#include <assert.h>

#include "common.h"
#include <sys/time.h>
#include "timing.h"

#include <string.h>
#include <string>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

extern void lud_diagonal(float *m, float *shadow, int matrix_dim, int offset);
extern void lud_perimeter(float *m, float *dia, float *peri_row, float *peri_col, int matrix_dim, int offset);
extern void lud_internal(float *m, float *peri_row, float *peri_col, int matrix_dim, int offset);

static int do_verify = 0;

static struct option long_options[] = {
      {"input", 1, NULL, 'i'},
      {"size", 1, NULL, 's'},
      {"verify", 0, NULL, 'v'},
      {"platform", 1, NULL, 'p'},
      {"device", 1, NULL, 'd'},
      {0,0,0,0}
};

int
main ( int argc, char *argv[] )
{
#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start;
    struct timeval tv_init_end;
    struct timeval tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
          d2h_time = 0, close_time = 0, total_time = 0;
#endif

    printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);
    size_t matrix_dim = 32; 
    int opt, option_index=0;
    func_ret_t ret;
    const char *input_file = NULL;
    float *m, *mm;
    stopwatch sw;
    int platform_id_inuse = 0;
    int device_id_inuse = 0;

    while ((opt = getopt_long(argc, argv, "::vs:i:p:d:", 
                            long_options, &option_index)) != -1 ) {
        switch(opt){
            case 'i':
                input_file = optarg;
                break;
            case 'v':
                do_verify = 1;
                break;
            case 's':
                matrix_dim = atoi(optarg);
                printf("Generate input matrix internally, size =%lu\n", matrix_dim);
                break;
            case 'p':
                platform_id_inuse = atoi(optarg);
                break;
            case 'd':
                device_id_inuse = atoi(optarg);
                break;
            case '?':
                fprintf(stderr, "invalid option\n");
                break;
            case ':':
                fprintf(stderr, "missing argument\n");
                break;
            default:
                fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n",
                  argv[0]);
                exit(EXIT_FAILURE);
        }
    }

    if ( (optind < argc) || (optind == 1)) {
        fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n", argv[0]);
        exit(EXIT_FAILURE);
    }	

    if (input_file) {
        printf("Reading matrix from file %s\n", input_file);
        ret = create_matrix_from_file(&m, input_file, (int*)&matrix_dim);
        if (ret != RET_SUCCESS) {
            m = NULL;
            fprintf(stderr, "error create matrix from file %s\n", input_file);
            exit(EXIT_FAILURE);
        }
    } 

    else if (matrix_dim) {
        printf("Creating matrix internally size=%lu\n", matrix_dim);
        ret = create_matrix(&m, matrix_dim);
        if (ret != RET_SUCCESS) {
            m = NULL;
            fprintf(stderr, "error create matrix internally size=%lu\n", matrix_dim);
            exit(EXIT_FAILURE);
        }
    }

    else {
        printf("No input file specified!\n");
        exit(EXIT_FAILURE);
    }

    if (do_verify){
        printf("Before LUD\n");
        matrix_duplicate(m, &mm, matrix_dim);
    }

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef  TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    float *d_m;
    cudaError_t err = cudaMalloc(&d_m, matrix_dim*matrix_dim * sizeof(float));
    if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_m (size:%lu) => %d\n", matrix_dim*matrix_dim, err); return -1;} 
#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    stopwatch_start(&sw);
    err = cudaMemcpy(d_m, m, matrix_dim*matrix_dim*sizeof(float), cudaMemcpyHostToDevice);
    if(err != cudaSuccess) { printf("ERROR: cudaMemcpy d_m (size:%lu) => %d\n", matrix_dim*matrix_dim, err); return -1; }
#ifdef TIMING
    h2d_time += 0.0;
#endif

    size_t i=0;
    for (i=0; i < matrix_dim-BLOCK_SIZE; i += BLOCK_SIZE) {
        float *shadow;
        cudaMalloc(&shadow, sizeof(float) * BLOCK_SIZE * BLOCK_SIZE);

        dim3 global_work1(BLOCK_SIZE, 1, 1);
        dim3 local_work1(BLOCK_SIZE, 1, 1);

        lud_diagonal<<<local_work1, global_work1>>>(d_m, shadow, matrix_dim, i);
        cudaError_t kernel_err = cudaGetLastError();
        if(kernel_err != cudaSuccess) { printf("ERROR: lud_diagonal kernel => %d failed\n", kernel_err); return -1; }	
#ifdef TIMING
        kernel_time += 0.0;
#endif

        cudaFree(shadow);

        float *dia, *peri_row, *peri_col;
        cudaMalloc(&dia, sizeof(float) * BLOCK_SIZE * BLOCK_SIZE);
        cudaMalloc(&peri_row, sizeof(float) * BLOCK_SIZE * BLOCK_SIZE);
        cudaMalloc(&peri_col, sizeof(float) * BLOCK_SIZE * BLOCK_SIZE);

        dim3 global_work2(BLOCK_SIZE * 2 * ((matrix_dim-i)/BLOCK_SIZE-1), 1, 1);
        dim3 local_work2(BLOCK_SIZE * 2, 1, 1);

        if (global_work2.x > 0) {
            lud_perimeter<<<local_work2, global_work2>>>(d_m, dia, peri_row, peri_col, matrix_dim, i);
            kernel_err = cudaGetLastError();
            if(kernel_err != cudaSuccess) { printf("ERROR: lud_perimeter kernel => %d failed\n", kernel_err); return -1; }	
#ifdef TIMING
            kernel_time += 0.0;
#endif
        }

        cudaFree(dia);
        cudaFree(peri_row);
        cudaFree(peri_col);

        cudaMalloc(&peri_row, sizeof(float) * BLOCK_SIZE * BLOCK_SIZE);
        cudaMalloc(&peri_col, sizeof(float) * BLOCK_SIZE * BLOCK_SIZE);

        dim3 global_work3(BLOCK_SIZE * ((matrix_dim-i)/BLOCK_SIZE-1), BLOCK_SIZE * ((matrix_dim-i)/BLOCK_SIZE-1), 1);
        dim3 local_work3(BLOCK_SIZE, BLOCK_SIZE, 1);

        if (global_work3.x > 0) {
            lud_internal<<<local_work3, global_work3>>>(d_m, peri_row, peri_col, matrix_dim, i);
            kernel_err = cudaGetLastError();
            if(kernel_err != cudaSuccess) { printf("ERROR: lud_internal kernel => %d failed\n", kernel_err); return -1; }	
#ifdef TIMING
            kernel_time += 0.0;
#endif
        }

        cudaFree(peri_row);
        cudaFree(peri_col);
    }

    float *shadow;
    cudaMalloc(&shadow, sizeof(float) * BLOCK_SIZE * BLOCK_SIZE);

    dim3 global_work1(BLOCK_SIZE, 1, 1);
    dim3 local_work1(BLOCK_SIZE, 1, 1);
    lud_diagonal<<<local_work1, global_work1>>>(d_m, shadow, matrix_dim, i);
    cudaError_t kernel_err = cudaGetLastError();
    if(kernel_err != cudaSuccess) { printf("ERROR: lud_diagonal kernel => %d failed\n", kernel_err); return -1; }	
#ifdef TIMING
    kernel_time += 0.0;
#endif

    cudaFree(shadow);

    cudaDeviceSynchronize();
    err = cudaMemcpy(m, d_m, matrix_dim*matrix_dim*sizeof(float), cudaMemcpyDeviceToHost);
    if(err != cudaSuccess) { printf("ERROR: cudaMemcpy d_m (size:%lu) => %d\n", matrix_dim*matrix_dim, err); return -1; }
#ifdef TIMING
    d2h_time += 0.0;
#endif

    cudaDeviceSynchronize();

#ifdef  TIMING
    gettimeofday(&tv_close_start, NULL);
#endif
    cudaFree(d_m);
#ifdef  TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    if (do_verify){
        printf("After LUD\n");
        printf(">>>Verify<<<<\n");
        lud_verify(mm, m, matrix_dim); 
        free(mm);
    }

    free(m);

}
